import express from 'express';

const app = express();

// Vulnerable SSRF pattern (do not use).
app.get('/api/preview', async (req, res) => {
  const raw = String(req.query.url || '');
  if (!raw) return res.status(400).json({ error: 'Missing url' });

  // Naive checks are bypassable (encoding tricks, alternate IP formats,
  // DNS changes, and redirects).
  if (!raw.startsWith('https://')) {
    return res.status(400).json({ error: 'https only' });
  }
  if (raw.includes('localhost') || raw.includes('127.0.0.1')) {
    return res.status(400).json({ error: 'local blocked' });
  }

  // Many HTTP clients follow redirects by default.
  const r = await fetch(raw);
  const body = await r.text();

  // Returning content can turn SSRF into direct data exfiltration.
  res.json({ status: r.status, sample: body.slice(0, 2000) });
});

app.listen(3000);

import dns from 'node:dns/promises';
import net from 'node:net';

const ALLOWED_HOSTS = new Set([
  'static.example.com',
  'images.examplecdn.com'
]);

function isPrivateOrLocalIp(ip) {
  const v = net.isIP(ip);
  if (v === 4) {
    const [a, b] = ip.split('.').map((n) => Number.parseInt(n, 10));
    if (!Number.isInteger(a) || !Number.isInteger(b)) return true;

    if (a === 10) return true;
    if (a === 127) return true;
    if (a === 169 && b === 254) return true; // link-local
    if (a === 172 && b >= 16 && b <= 31) return true;
    if (a === 192 && b === 168) return true;
    return false;
  }

  if (v === 6) {
    const s = ip.toLowerCase();
    if (s === '::1') return true;
    if (s.startsWith('fe80:')) return true; // link-local
    if (s.startsWith('fc') || s.startsWith('fd')) return true; // ULA
    return false;
  }

  // Treat non-IP as unsafe.
  return true;
}

async function assertSafeOutboundUrl(rawUrl) {
  let u;
  try {
    u = new URL(rawUrl);
  } catch {
    throw new Error('Invalid URL');
  }

  if (u.protocol !== 'https:') throw new Error('Only https is allowed');
  if (u.username || u.password) throw new Error('Userinfo not allowed');
  if (!ALLOWED_HOSTS.has(u.hostname)) throw new Error('Host not allowed');
  if (u.port && u.port !== '443') throw new Error('Port not allowed');

  // Resolve and block private or local ranges.
  const addrs = await dns.lookup(u.hostname, { all: true, verbatim: true });
  if (addrs.length === 0) throw new Error('No DNS results');

  for (const a of addrs) {
    if (isPrivateOrLocalIp(a.address)) {
      throw new Error(`Unsafe DNS result: ${a.address}`);
    }
  }

  return u;
}

export async function safeFetchPreview(rawUrl, {
  timeoutMs = 2000,
  maxBytes = 128 * 1024
} = {}) {
  const u = await assertSafeOutboundUrl(rawUrl);

  const r = await fetch(u.toString(), {
    method: 'GET',
    redirect: 'manual',
    signal: AbortSignal.timeout(timeoutMs),
    headers: {
      'User-Agent': 'PreviewFetcher/1.0',
      'Accept': 'text/html, text/plain;q=0.9, */*;q=0.1'
    }
  });

  if (r.status >= 300 && r.status < 400) {
    throw new Error('Redirects not allowed');
  }

  // Stream with a strict size limit to reduce DoS and memory risk.
  const reader = r.body?.getReader?.();
  if (!reader) {
    const t = await r.text();
    return t.slice(0, maxBytes);
  }

  let total = 0;
  const chunks = [];

  while (true) {
    const { value, done } = await reader.read();
    if (done) break;

    total += value.byteLength;
    if (total > maxBytes) throw new Error('Response too large');
    chunks.push(value);
  }

  const merged = new Uint8Array(total);
  let off = 0;
  for (const c of chunks) {
    merged.set(c, off);
    off += c.byteLength;
  }

  return new TextDecoder('utf-8', { fatal: false }).decode(merged);
}

