const DEFAULT_NEXT = '/';

export function safeNextPath(input) {
  if (typeof input !== 'string') return DEFAULT_NEXT;

  const next = input.trim();
  if (!next) return DEFAULT_NEXT;
  if (next.length > 2048) return DEFAULT_NEXT;

  // Allow only same-origin paths.
  if (!next.startsWith('/')) return DEFAULT_NEXT;
  if (next.startsWith('//')) return DEFAULT_NEXT; // scheme-relative
  if (next.includes('\\')) return DEFAULT_NEXT; // normalization tricks

  // Optional tightening: allow only known in-app destinations.
  const allowedPrefixes = ['/app', '/settings', '/dashboard', '/'];
  const ok = allowedPrefixes.some((p) => next === p || next.startsWith(p + '/'));
  return ok ? next : DEFAULT_NEXT;
}

