# Conceptual NGINX hardening example. Validate in staging.
# Goal: reject ambiguous framing and reduce desync risk.

server {
  listen 443 ssl;

  # If your clients do not require chunked uploads, reject Transfer-Encoding.
  if ($http_transfer_encoding != "") {
    return 400;
  }

  # Multiple Content-Length values are often rendered like "123, 456".
  if ($http_content_length ~ ",") {
    return 400;
  }

  client_header_timeout 10s;
  client_body_timeout 10s;

  location / {
    proxy_http_version 1.1;

    # Remove hop-by-hop semantics.
    proxy_set_header Connection "";

    # Buffer full requests before sending upstream to improve normalization.
    proxy_request_buffering on;

    proxy_pass http://app_backend;
  }
}

